//! Hand-written wasm-bindgen dispatch glue.
//!
//! This module is NOT regenerated by alef. It owns the JS-host integration
//! boundary: converting `JsValue` requests into `http::Request<axum::body::Body>`,
//! driving the `axum::Router` as a `tower::Service` via `Router::call`, and
//! converting the resulting `http::Response` back to `JsValue` for the host.
//!
//! Pattern follows axum-cloudflare-adapter / workers-rs `http` feature: bypass
//! `axum::serve` (which requires hyper + mio) and call the router directly.
//! The host is responsible for owning the socket — wasm32 cannot bind one.

use std::cell::RefCell;

use axum::Router;
use axum::body::Body;
use axum::http::{Request, Response};
use tower::Service;
use wasm_bindgen::prelude::*;

thread_local! {
    /// Per-isolate router instance. Set via `set_router` once at module init,
    /// then reused for every `handle_request` call. Each Worker isolate has its
    /// own thread-local, so this is safe under concurrent fetch events.
    static ROUTER: RefCell<Option<Router>> = const { RefCell::new(None) };
}

/// Install a router for this isolate. Must be called before `handle_request`.
/// In a typical Cloudflare Workers setup this happens once during module init.
pub fn set_router(router: Router) {
    ROUTER.with(|cell| {
        *cell.borrow_mut() = Some(router);
    });
}

/// Dispatch an HTTP request through the installed router.
///
/// Input shape (JsValue): `{ method, url, headers: { [k]: v }, body?: Uint8Array | string | null }`.
/// Output shape (JsValue): `{ status, headers: { [k]: v }, body: Uint8Array }`.
///
/// Errors are returned as `JsValue::from_str(msg)` and propagate as JS
/// `Error` instances at the wasm-bindgen boundary.
#[wasm_bindgen]
pub async fn handle_request(req: JsValue) -> Result<JsValue, JsValue> {
    let mut router = ROUTER
        .with(|cell| cell.borrow().clone())
        .ok_or_else(|| JsValue::from_str("router not initialized — call set_router first"))?;

    let http_req = js_to_http_request(req)?;
    let http_resp = router
        .call(http_req)
        .await
        .map_err(|e| JsValue::from_str(&format!("router error: {e}")))?;
    http_response_to_js(http_resp).await
}

fn js_to_http_request(req: JsValue) -> Result<Request<Body>, JsValue> {
    let parsed: JsRequest =
        serde_wasm_bindgen::from_value(req).map_err(|e| JsValue::from_str(&format!("invalid request shape: {e}")))?;

    let method: axum::http::Method = parsed
        .method
        .parse()
        .map_err(|e| JsValue::from_str(&format!("invalid method: {e}")))?;

    let mut builder = Request::builder().method(method).uri(parsed.url.as_str());

    if let Some(headers) = builder.headers_mut() {
        for (name, value) in parsed.headers {
            let header_name: axum::http::HeaderName = name
                .parse()
                .map_err(|e| JsValue::from_str(&format!("invalid header name '{name}': {e}")))?;
            let header_value: axum::http::HeaderValue = value
                .parse()
                .map_err(|e| JsValue::from_str(&format!("invalid header value for '{name}': {e}")))?;
            headers.insert(header_name, header_value);
        }
    }

    let body = parsed.body.unwrap_or_default();
    builder
        .body(Body::from(body))
        .map_err(|e| JsValue::from_str(&format!("failed to build request: {e}")))
}

async fn http_response_to_js(resp: Response<Body>) -> Result<JsValue, JsValue> {
    let (parts, body) = resp.into_parts();
    let body_bytes = http_body_util::BodyExt::collect(body)
        .await
        .map_err(|e| JsValue::from_str(&format!("failed to read response body: {e}")))?
        .to_bytes()
        .to_vec();

    let headers: Vec<(String, String)> = parts
        .headers
        .iter()
        .map(|(name, value)| {
            let value_str = value.to_str().unwrap_or_default().to_string();
            (name.as_str().to_string(), value_str)
        })
        .collect();

    let response = JsResponse {
        status: parts.status.as_u16(),
        headers,
        body: body_bytes,
    };

    serde_wasm_bindgen::to_value(&response)
        .map_err(|e| JsValue::from_str(&format!("failed to serialize response: {e}")))
}

#[derive(serde::Deserialize)]
struct JsRequest {
    method: String,
    url: String,
    #[serde(default)]
    headers: Vec<(String, String)>,
    #[serde(default)]
    body: Option<Vec<u8>>,
}

#[derive(serde::Serialize)]
struct JsResponse {
    status: u16,
    headers: Vec<(String, String)>,
    #[serde(with = "serde_bytes")]
    body: Vec<u8>,
}
